67	architecture rtl of olo_fix_mix_c2r is
68	
69	    -- Formats
70	    constant EntityName_c : string      := "olo_fix_mix_c2r";
71	    constant InFmt_c      : FixFormat_t := cl_fix_format_from_string(InFmt_g);
72	    constant MixFmt_c     : FixFormat_t := cl_fix_format_from_string(MixFmt_g);
73	    constant OutFmt_c     : FixFormat_t := cl_fix_format_from_string(OutFmt_g);
74	
75	    -- Multiply and chain formats (same structure as olo_fix_cplx_mult MULT4)
76	    constant MultFmt_c  : FixFormat_t := cl_fix_mult_fmt(InFmt_c, MixFmt_c);
77	    constant ChainFmt_c : FixFormat_t := cl_fix_addsub_fmt(MultFmt_c, MultFmt_c);
78	
79	    -- Round/Sat registers
80	    constant RoundReg_c : string := choose(compareNoCase(Round_g, FixRound_Trunc_c), "NO", "YES");
81	    constant SatReg_c   : string := choose(compareNoCase(Saturate_g, FixSaturate_Warn_c) or
82	                                           compareNoCase(Saturate_g, FixSaturate_None_c), "NO", "YES");
83	
84	begin
85	
86	    -- Assertions
87	    -- synthesis translate_off
88	    assert compareNoCase(IqHandling_g, "Parallel") or compareNoCase(IqHandling_g, "TDM")
89	        report errorMessage(EntityName_c, "Invalid IqHandling_g: " & IqHandling_g)
90	        severity error;
91	    -- synthesis translate_on
92	
93	    -----------------------------------------------------------------------------------------------
94	    -- Parallel I/Q Architecture
95	    -----------------------------------------------------------------------------------------------
96	    g_parallel : if compareNoCase(IqHandling_g, "Parallel") generate
97	
98	        signal In_Valid_0 : std_logic;
99	        signal In_SigQ_0  : std_logic_vector(In_SigQ'range);
100	        signal In_MixQ_0  : std_logic_vector(In_MixQ'range);
101	
102	        signal II_Out_N1    : std_logic_vector(cl_fix_width(ChainFmt_c) - 1 downto 0);
103	        signal Real_Full_N2 : std_logic_vector(cl_fix_width(ChainFmt_c) - 1 downto 0);
104	        signal Valid_N2     : std_logic;
105	
106	    begin
107	
108	        -- Pipeline stage
109	        p_reg : process (Clk) is
110	        begin
111	            if rising_edge(Clk) then
112	                -- Normal Operation
113	                In_Valid_0 <= In_Valid;
114	                In_SigQ_0  <= In_SigQ;
115	                In_MixQ_0  <= In_MixQ;
116	
117	                -- Reset
118	                if Rst = '1' then
119	                    In_Valid_0 <= '0';
120	                end if;
121	            end if;
122	        end process;
123	
124	        -- I x I multiplication
125	        i_ii : entity work.olo_fix_madd
126	            generic map (
127	                AFmt_g        => InFmt_g,
128	                BFmt_g        => MixFmt_g,
129	                AddChainFmt_g => to_string(ChainFmt_c),
130	                MultRegs_g    => MultRegs_g
131	            )
132	            port map (
133	                Clk        => Clk,
134	                Rst        => Rst,
135	                InAC_Valid => In_Valid,
136	                InA_Data   => In_SigI,
137	                InB_Valid  => In_Valid,
138	                InB_Data   => In_MixI,
139	                Out_Data   => II_Out_N1
140	            );
141	
142	        -- Q x Q multiplication (+ accumulation)
143	        i_qq : entity work.olo_fix_madd
144	            generic map (
145	                AFmt_g        => InFmt_g,
146	                BFmt_g        => MixFmt_g,
147	                AddChainFmt_g => to_string(ChainFmt_c),
148	                Operation_g   => "Add",
149	                MultRegs_g    => MultRegs_g
150	            )
151	            port map (
152	                Clk        => Clk,
153	                Rst        => Rst,
154	                InAC_Valid => In_Valid_0,
155	                InA_Data   => In_SigQ_0,
156	                InB_Valid  => In_Valid_0,
157	                InB_Data   => In_MixQ_0,
158	                MaccIn     => II_Out_N1,
159	                Out_Data   => Real_Full_N2,
160	                Out_Valid  => Valid_N2
161	            );
162	
163	        -- Resize to output format
164	        i_resize : entity work.olo_fix_resize
165	            generic map (
166	                AFmt_g      => to_string(ChainFmt_c),
167	                ResultFmt_g => OutFmt_g,
168	                Round_g     => Round_g,
169	                Saturate_g  => Saturate_g,
170	                RoundReg_g  => RoundReg_c,
171	                SatReg_g    => SatReg_c
172	            )
173	            port map (
174	                Clk        => Clk,
175	                Rst        => Rst,
176	                In_Valid   => Valid_N2,
177	                In_A       => Real_Full_N2,
178	                Out_Valid  => Out_Valid,
179	                Out_Result => Out_SigReal
180	            );
181	
182	    end generate;
183	
184	    -----------------------------------------------------------------------------------------------
185	    -- TDM I/Q Architecture
186	    -----------------------------------------------------------------------------------------------
187	    g_tdm : if compareNoCase(IqHandling_g, "TDM") generate
188	
189	        constant SumFmt_c : FixFormat_t := cl_fix_addsub_fmt(MultFmt_c, MultFmt_c);
190	        constant Stages_c : natural     := MultRegs_g + 2;
191	
192	        signal IsQ           : std_logic;
193	        signal Valid_I       : std_logic_vector(0 to Stages_c - 1);
194	        signal Valid_Q       : std_logic_vector(0 to Stages_c - 1);
195	        signal InSig_0       : std_logic_vector(In_SigIQ'range);
196	        signal InMix_0       : std_logic_vector(In_MixIQ'range);
197	        signal MultI_N0      : std_logic_vector(cl_fix_width(MultFmt_c) - 1 downto 0);
198	        signal MultI_Hold_N1 : std_logic_vector(cl_fix_width(MultFmt_c) - 1 downto 0);
199	        signal AddI_N1       : std_logic_vector(cl_fix_width(SumFmt_c) - 1 downto 0);
200	        signal MultI_Valid   : std_logic;
201	
202	        attribute use_dsp                    : string;
203	        attribute use_dsp of AddI_N1 : signal is "no";
204	
205	    begin
206	
207	        -- Clocked process
208	        p_reg : process (Clk) is
209	        begin
210	            if rising_edge(Clk) then
211	
212	                -- Shift valids
213	                Valid_I(0)                 <= In_Valid and not IsQ;
214	                Valid_Q(0)                 <= In_Valid and IsQ;
215	                Valid_I(1 to Valid_I'high) <= Valid_I(0 to Valid_I'high - 1);
216	                Valid_Q(1 to Valid_Q'high) <= Valid_Q(0 to Valid_Q'high - 1);
217	
218	                -- I/Q detection
219	                if In_Valid = '1' then
220	                    if In_Last = '1' then
221	                        IsQ <= '0';
222	                    else
223	                        IsQ <= not IsQ;
224	                    end if;
225	                end if;
226	
227	                -- Input registers
228	                if In_Valid = '1' then
229	                    InSig_0 <= In_SigIQ;
230	                    InMix_0 <= In_MixIQ;
231	                end if;
232	
233	                -- I path: hold SigI*MixI until Q sample arrives
234	                if Valid_I(MultRegs_g) = '1' then
235	                    MultI_Hold_N1 <= MultI_N0;
236	                end if;
237	
238	                -- I path: accumulate SigI*MixI + SigQ*MixQ (MIX mode: add)
239	                if Valid_Q(MultRegs_g) = '1' then
240	                    AddI_N1 <= cl_fix_add(MultI_Hold_N1, MultFmt_c, MultI_N0, MultFmt_c, SumFmt_c);
241	                end if;
242	
243	                -- Reset
244	                if Rst = '1' then
245	                    IsQ     <= '0';
246	                    Valid_I <= (others => '0');
247	                    Valid_Q <= (others => '0');
248	                end if;
249	
250	            end if;
251	        end process;
252	
253	        -- Multiplier: alternates between SigI*MixI and SigQ*MixQ
254	        MultI_Valid <= Valid_I(0) or Valid_Q(0);
255	
256	        i_mult_i : entity work.olo_fix_mult
257	            generic map (
258	                AFmt_g      => InFmt_g,
259	                BFmt_g      => MixFmt_g,
260	                ResultFmt_g => to_string(MultFmt_c),
261	                OpRegs_g    => MultRegs_g,
262	                RoundReg_g  => "NO",
263	                SatReg_g    => "NO"
264	            )
265	            port map (
266	                Clk        => Clk,
267	                Rst        => Rst,
268	                In_Valid   => MultI_Valid,
269	                In_A       => InSig_0,
270	                In_B       => InMix_0,
271	                Out_Result => MultI_N0
272	            );
273	
274	        -- Resize to output format
275	        i_resize : entity work.olo_fix_resize
276	            generic map (
277	                AFmt_g      => to_string(SumFmt_c),
278	                ResultFmt_g => OutFmt_g,
279	                Round_g     => Round_g,
280	                Saturate_g  => Saturate_g,
281	                RoundReg_g  => RoundReg_c,
282	                SatReg_g    => SatReg_c
283	            )
284	            port map (
285	                Clk        => Clk,
286	                Rst        => Rst,
287	                In_Valid   => Valid_Q(MultRegs_g + 1),
288	                In_A       => AddI_N1,
289	                Out_Valid  => Out_Valid,
290	                Out_Result => Out_SigReal
291	            );
292	
293	    end generate;
294	
295	end architecture;
