        report errorMessage(EntityName_c, "Invalid IqHandling_g: " & IqHandling_g)
        severity error;
    -- synthesis translate_on

    -----------------------------------------------------------------------------------------------
    -- Parallel I/Q Architecture
    -----------------------------------------------------------------------------------------------
