4	-- Authors: Oliver Bruendler
5	---------------------------------------------------------------------------------------------------
6	
7	---------------------------------------------------------------------------------------------------
8	-- Description
9	---------------------------------------------------------------------------------------------------
10	-- This entity implements a rotating CORDIC algorithm in either pipelined or serial mode.
11	--
12	-- Documentation:
13	-- https://github.com/open-logic/open-logic/blob/main/doc/fix/olo_fix_cordic_rot.md
14	--
15	-- Note: The link points to the documentation of the latest release. If you
16	--       use an older version, the documentation might not match the code.
17	
18	---------------------------------------------------------------------------------------------------
19	-- Libraries
20	---------------------------------------------------------------------------------------------------
21	library ieee;
22	    use ieee.std_logic_1164.all;
23	    use ieee.numeric_std.all;
24	    use ieee.math_real.all;
25	
26	library work;
27	    use work.olo_base_pkg_math.all;
28	    use work.olo_base_pkg_string.all;
29	    use work.olo_base_pkg_array.all;
30	    use work.en_cl_fix_pkg.all;
31	    use work.olo_fix_pkg.all;
32	
33	---------------------------------------------------------------------------------------------------
34	-- Entity Declaration
35	---------------------------------------------------------------------------------------------------
36	entity olo_fix_cordic_rot is
37	    generic (
38	        InMagFmt_g        : string;
39	        InAngFmt_g        : string;
40	        OutFmt_g          : string;
41	        IntXyFmt_g        : string                 := "AUTO";
42	        IntAngFmt_g       : string                 := "AUTO";
43	        Iterations_g      : positive range 3 to 32 := 16;
44	        Mode_g            : string                 := "PIPELINED";
45	        GainCorrCoefFmt_g : string                 := "(0,0,17)";
46	        Round_g           : string                 := FixRound_Trunc_c;
47	        Saturate_g        : string                 := FixSaturate_Warn_c
48	    );
49	    port (
50	        -- Control Signals
51	        Clk       : in    std_logic;
52	        Rst       : in    std_logic;
53	        -- Input
54	        In_Valid  : in    std_logic := '1';
55	        In_Ready  : out   std_logic;
56	        In_Mag    : in    std_logic_vector(fixFmtWidthFromString(InMagFmt_g)-1 downto 0);
57	        In_Ang    : in    std_logic_vector(fixFmtWidthFromString(InAngFmt_g)-1 downto 0);
58	        -- Output
59	        Out_Valid : out   std_logic;
60	        Out_I     : out   std_logic_vector(fixFmtWidthFromString(OutFmt_g)-1 downto 0);
61	        Out_Q     : out   std_logic_vector(fixFmtWidthFromString(OutFmt_g)-1 downto 0)
62	    );
63	end entity;
64	
65	---------------------------------------------------------------------------------------------------
66	-- Architecture Declaration
67	---------------------------------------------------------------------------------------------------
68	architecture rtl of olo_fix_cordic_rot is
69	
70	    -- Formats
71	    constant EntityName_c      : string        := "olo_fix_cordic_rot";
72	    constant InMagFmt_c        : FixFormat_t   := cl_fix_format_from_string(InMagFmt_g);
73	    constant InAngFmt_c        : FixFormat_t   := cl_fix_format_from_string(InAngFmt_g);
74	    constant OutFmt_c          : FixFormat_t   := cl_fix_format_from_string(OutFmt_g);
75	    constant IntXyFmt_c        : FixFormat_t   := choose(compareNoCase(IntXyFmt_g, "AUTO"),
76	                                                         (1, InMagFmt_c.I + 1, OutFmt_c.F + 3),
77	                                                         fixFmtFromStringTolerant(IntXyFmt_g));
78	    constant IntAngFmt_c       : FixFormat_t   := choose(compareNoCase(IntAngFmt_g, "AUTO"),
79	                                                         (1, -2, InAngFmt_c.F + 3),
80	                                                         fixFmtFromStringTolerant(IntAngFmt_g));
81	    constant GainCorrCoefFmt_c : FixFormat_t   := choose(compareNoCase(GainCorrCoefFmt_g, "NONE"),
82	                                                         FixFmt_Unused_c,
83	                                                         fixFmtFromStringTolerant(GainCorrCoefFmt_g));
84	    constant Round_c           : FixRound_t    := cl_fix_round_from_string(Round_g);
85	    constant Saturate_c        : FixSaturate_t := cl_fix_saturate_from_string(Saturate_g);
86	
87	    -- Constants
88	    constant AngleTableReal_c : RealArray_t(0 to 31) := (0.125,                 0.0737918088252,    0.0389895651887,    0.0197917120803,
89	                                                         0.00993426215277,    0.00497197391179,    0.00248659363948,    0.00124337269683,
90	                                                         0.000621695834357,    0.000310849102962,    0.000155424699705,    7.77123683806e-05,
91	                                                         3.88561865063e-05,    1.94280935426e-05,    9.71404680751e-06,    4.85702340828e-06,
92	                                                         2.4285117047e-06,    1.21425585242e-06,    6.0712792622e-07,    3.03563963111e-07,
93	                                                         1.51781981556e-07,    7.58909907779e-08,    3.7945495389e-08,    1.89727476945e-08,
94	                                                         9.48637384724e-09,    4.74318692362e-09,    2.37159346181e-09,    1.1857967309e-09,
95	                                                         5.92898365452e-10,    2.96449182726e-10,    1.48224591363e-10,    7.41122956816e-11);
96	    type AngleTable_t is array (0 to Iterations_g-1) of std_logic_vector(cl_fix_width(IntAngFmt_c)-1 downto 0);
97	
98	    function angleTableStdlv return AngleTable_t is
99	        variable Table_v : AngleTable_t;
100	    begin
101	
102	        for i in 0 to Iterations_g-1 loop
103	            Table_v(i) := cl_fix_from_real(AngleTableReal_c(i), IntAngFmt_c);
104	        end loop;
105	
106	        return Table_v;
107	    end function;
108	
109	    constant AngleTable_c : AngleTable_t := angleTableStdlv;
110	
111	    function cordicGain (iterations : integer) return real is
112	        variable Gain_v : real := 1.0;
113	    begin
114	
115	        for i in 0 to iterations-1 loop
116	            Gain_v := Gain_v * sqrt(1.0+2.0**(-2.0*real(i)));
117	        end loop;
118	
119	        return Gain_v;
120	    end function;
121	
122	    constant GcCoef_c  : std_logic_vector(cl_fix_width(GainCorrCoefFmt_c)-1 downto 0) := cl_fix_from_real(1.0/cordicGain(Iterations_g), GainCorrCoefFmt_c);
123	    constant QuadFmt_c : FixFormat_t                                                  := (0, 0, 2);
124	
125	    -- *** Functions ***
126	    -- Cordic step for X
127	    function cordicStepx (
128	        xLast        : std_logic_vector;
129	        yLast        : std_logic_vector;
130	        zLast        : std_logic_vector;
131	        shift        : integer) return std_logic_vector is
132	        -- Declarations
133	        constant YShifted_c : std_logic_vector := fixDynShift(yLast, IntXyFmt_c, -shift, -Iterations_g, 0, IntXyFmt_c, Trunc_s, None_s);
134	    begin
135	
136	        if signed(zLast) > 0 then
137	            return cl_fix_sub(xLast, IntXyFmt_c,
138	                             YShifted_c, IntXyFmt_c,
139	                             IntXyFmt_c, Trunc_s, None_s);
140	        else
141	            return cl_fix_add(xLast, IntXyFmt_c,
142	                             YShifted_c, IntXyFmt_c,
143	                             IntXyFmt_c, Trunc_s, None_s);
144	
145	        end if;
146	    end function;
147	
148	    -- Cordic step for Y
149	    function cordicStepy (
150	        xLast        : std_logic_vector;
151	        yLast        : std_logic_vector;
152	        zLast        : std_logic_vector;
153	        shift        : integer) return std_logic_vector is
154	        -- Declarations
155	        constant XShifted_c : std_logic_vector := fixDynShift(xLast, IntXyFmt_c, -shift, -Iterations_g, 0, IntXyFmt_c, Trunc_s, None_s);
156	    begin
157	
158	        if signed(zLast) > 0 then
159	            return    cl_fix_add(yLast, IntXyFmt_c,
160	                                XShifted_c, IntXyFmt_c,
161	                                IntXyFmt_c, Trunc_s, None_s);
162	        else
163	            return    cl_fix_sub(yLast, IntXyFmt_c,
164	                                XShifted_c, IntXyFmt_c,
165	                                IntXyFmt_c, Trunc_s, None_s);
166	        end if;
167	    end function;
168	
169	    -- Cordic step for Z
170	    function cordicStepz (
171	        zLast        : std_logic_vector;
172	        iteration    : integer) return std_logic_vector is
173	        -- Declarations
174	        constant Atan_c : std_logic_vector(cl_fix_width(IntAngFmt_c)-1 downto 0) := AngleTable_c(iteration);
175	    begin
176	        if signed(zLast) > 0 then
177	            return    cl_fix_sub(zLast, IntAngFmt_c,
178	                                Atan_c, IntAngFmt_c,
179	                                IntAngFmt_c, Trunc_s, None_s);
180	        else
181	            return    cl_fix_add(zLast, IntAngFmt_c,
182	                                Atan_c, IntAngFmt_c,
183	                                IntAngFmt_c, Trunc_s, None_s);
184	        end if;
185	    end function;
186	
187	    -- Types
188	    type IntArr_t is array (natural range <>) of std_logic_vector(cl_fix_width(IntXyFmt_c)-1 downto 0);
189	    type AngArr_t is array (natural range <>) of std_logic_vector(cl_fix_width(IntAngFmt_c)-1 downto 0);
190	
191	    -- Gain Correction Signals
192	    signal YQc, XQc   : std_logic_vector(cl_fix_width(IntXyFmt_c)-1 downto 0);
193	    signal QcVld      : std_logic;
194	    signal In_Ready_I : std_logic;
195	    signal ProcMag    : std_logic_vector(cl_fix_width(IntXyFmt_c)-1 downto 0);
196	    signal ProcValid  : std_logic;
197	    signal ProcAng    : std_logic_vector(cl_fix_width(InAngFmt_c)-1 downto 0);
198	
199	begin
200	
201	    -- *** Assertions ***
202	    assert InMagFmt_c.S = 0
203	        report errorMessage(EntityName_c, "InMagFmt_g must be unsigned")
204	        severity error;
205	    assert InAngFmt_c.S = 0
206	        report errorMessage(EntityName_c, "InAngFmt_g must be (0,0,x))")
207	        severity error;
208	    assert InAngFmt_c.I = 0
209	        report errorMessage(EntityName_c, "InAngFmt_g must be (0,0,x))")
210	        severity error;
211	    assert IntXyFmt_c.S = 1
212	        report errorMessage(EntityName_c, "IntXyFmt_g must be signed")
213	        severity error;
214	    assert IntAngFmt_c.S = 1
215	        report errorMessage(EntityName_c, "IntAngFmt_g must be sig(1,-2,x)ned")
216	        severity error;
217	    assert IntAngFmt_c.I = -2
218	        report errorMessage(EntityName_c, "IntAngFmt_g must be (1,-2,x)")
219	        severity error;
220	    assert compareNoCase(Mode_g, "PIPELINED") or compareNoCase(Mode_g, "SERIAL")
221	        report errorMessage(EntityName_c, "Mode_g must be PIPELINED or SERIAL")
222	        severity error;
223	
224	    -- *** Pipelined Implementation ***
225	    g_pipelined : if compareNoCase(Mode_g, "PIPELINED") generate
226	        signal X, Y : IntArr_t(0 to Iterations_g);
227	        signal Z    : AngArr_t(0 to Iterations_g);
228	        signal Vld  : std_logic_vector(0 to Iterations_g);
229	        signal Quad : StlvArray2_t(0 to Iterations_g);
230	    begin
231	        -- Pipelined implementation can take a sample every clock cycle
232	        In_Ready_I <= '1';
233	
234	        -- Implementation
235	        p_cordic_pipelined : process (Clk) is
236	        begin
237	            if rising_edge(Clk) then
238	                -- Initialization
239	                X(0)    <= ProcMag;
240	                Y(0)    <= (others => '0');
241	                Z(0)    <= cl_fix_resize(ProcAng, InAngFmt_c, IntAngFmt_c, Trunc_s, None_s);
242	                Quad(0) <= cl_fix_resize(ProcAng, InAngFmt_c, QuadFmt_c, Trunc_s, None_s);
243	                Vld(0)  <= ProcValid;
244	
245	                -- Cordic Iterations_g
246	                Vld(1 to Vld'high)   <= Vld(0 to Vld'high-1);
247	                Quad(1 to Quad'high) <= Quad(0 to Quad'high-1);
248	
249	                for i in 0 to Iterations_g-1 loop
250	                    X(i+1) <= cordicStepx(X(i), Y(i), Z(i), i);
251	                    Y(i+1) <= cordicStepy(X(i), Y(i), Z(i), i);
252	                    Z(i+1) <= cordicStepz(Z(i), i);
253	                end loop;
254	
255	                -- Quadrant Correction
256	                QcVld <= Vld(Iterations_g);
257	                if (Quad(Iterations_g) = "00") or (Quad(Iterations_g) = "11") then
258	                    YQc <= Y(Iterations_g);
259	                    XQc <= X(Iterations_g);
260	                else
261	                    YQc <= cl_fix_neg(Y(Iterations_g), IntXyFmt_c, IntXyFmt_c, Trunc_s, None_s);
262	                    XQc <= cl_fix_neg(X(Iterations_g), IntXyFmt_c, IntXyFmt_c, Trunc_s, None_s);
263	                end if;
264	
265	                if Rst = '1' then
266	                    Vld   <= (others => '0');
267	                    QcVld <= '0';
268	                end if;
269	            end if;
270	        end process;
271	
272	    end generate;
273	
274	    -- *** Serial Implementation ***
275	    g_serial : if compareNoCase(Mode_g, "SERIAL") generate
276	        signal Xin, Yin   : std_logic_vector(cl_fix_width(IntXyFmt_c)-1 downto 0);
277	        signal Zin        : std_logic_vector(cl_fix_width(IntAngFmt_c)-1 downto 0);
278	        signal XIn_Valid  : std_logic;
279	        signal Quadin     : std_logic_vector(1 downto 0);
280	        signal X, Y       : std_logic_vector(cl_fix_width(IntXyFmt_c)-1 downto 0);
281	        signal Z          : std_logic_vector(cl_fix_width(IntAngFmt_c)-1 downto 0);
282	        signal CordVld    : std_logic;
283	        signal IterCnt    : integer range 0 to Iterations_g-1;
284	        signal Quad       : std_logic_vector(1 downto 0);
285	        signal InReadyCnt : integer range 0 to Iterations_g-1;
286	    begin
287	
288	        p_cordic_serial : process (Clk) is
289	        begin
290	            if rising_edge(Clk) then
291	                -- In Ready Handling
292	                if In_Ready_I = '1' and In_Valid = '1' then
293	                    In_Ready_I <= '0';
294	                    InReadyCnt <= 0;
295	                end if;
296	
297	                if In_Ready_I = '0' then
298	                    InReadyCnt <= InReadyCnt + 1;
299	                    -- Block for Iterations_g-1 cycles
300	                    if InReadyCnt = Iterations_g - 2 then
301	                        In_Ready_I <= '1';
302	                    end if;
303	                end if;
304	
305	                -- Input latching
306	                if XIn_Valid = '0' and ProcValid = '1' then
307	                    XIn_Valid <= '1';
308	                    Xin       <= ProcMag;
309	                    Yin       <= (others => '0');
310	                    Zin       <= cl_fix_resize(ProcAng, InAngFmt_c, IntAngFmt_c, Trunc_s, None_s);
311	                    Quadin    <= cl_fix_resize(ProcAng, InAngFmt_c, QuadFmt_c, Trunc_s, None_s);
312	                end if;
313	
314	                -- CORDIC loop
315	                CordVld <= '0';
316	                if IterCnt = 0 then
317	                    -- start of calculation
318	                    if XIn_Valid = '1' then
319	                        X         <= cordicStepx(Xin, Yin, Zin, 0);
320	                        Y         <= cordicStepy(Xin, Yin, Zin, 0);
321	                        Quad      <= Quadin;
322	                        Z         <= cordicStepz(Zin, 0);
323	                        IterCnt   <= IterCnt+1;
324	                        XIn_Valid <= '0';
325	                    end if;
326	                else
327	                    -- Normal Calculation Step
328	                    X <= cordicStepx(X, Y, Z, IterCnt);
329	                    Y <= cordicStepy(X, Y, Z, IterCnt);
330	                    Z <= cordicStepz(Z, IterCnt);
331	
332	                    if IterCnt = Iterations_g-1 then
333	                        IterCnt <= 0;
334	                        CordVld <= '1';
335	                    else
336	                        IterCnt <= IterCnt+1;
337	                    end if;
338	                end if;
339	
340	                -- Quadrant Correction
341	                QcVld <= CordVld;
342	                if (Quad = "00") or (Quad = "11") then
343	                    YQc <= Y;
344	                    XQc <= X;
345	                else
346	                    YQc <= cl_fix_neg(Y, IntXyFmt_c, IntXyFmt_c, Trunc_s, None_s);
347	                    XQc <= cl_fix_neg(X, IntXyFmt_c, IntXyFmt_c, Trunc_s, None_s);
348	                end if;
349	
350	                -- Reset
351	                if Rst = '1' then
352	                    XIn_Valid  <= '0';
353	                    IterCnt    <= 0;
354	                    CordVld    <= '0';
355	                    QcVld      <= '0';
356	                    In_Ready_I <= '1';
357	                end if;
358	            end if;
359	        end process;
360	
361	    end generate;
362	
363	    In_Ready <= In_Ready_I;
364	
365	    -- *** Gain Correction and Input registers***
366	    -- Compensation Enabled
367	    g_gain_comp : if not compareNoCase(GainCorrCoefFmt_g, "NONE") generate
368	        signal In_Mag_Reg   : std_logic_vector(cl_fix_width(InMagFmt_c)-1 downto 0);
369	        signal In_Ang_Reg   : std_logic_vector(cl_fix_width(InAngFmt_c)-1 downto 0);
370	        signal In_Valid_Reg : std_logic;
371	    begin
372	
373	        p_registers : process (Clk) is
374	        begin
375	            if rising_edge(Clk) then
376	                -- Input Regiseter
377	                In_Mag_Reg   <= In_Mag;
378	                In_Ang_Reg   <= In_Ang;
379	                In_Valid_Reg <= In_Ready_I and In_Valid;
380	
381	                -- Compensate multiplier latency
382	                ProcAng <= In_Ang_Reg;
383	
384	                -- Reset
385	                if Rst = '1' then
386	                    In_Valid_Reg <= '0';
387	                end if;
388	            end if;
389	        end process;
390	
391	        i_mult_i : entity work.olo_fix_mult
392	            generic map (
393	                AFmt_g      => to_string(InMagFmt_c),
394	                BFmt_g      => to_string(GainCorrCoefFmt_c),
395	                ResultFmt_g => to_string(IntXyFmt_c),
396	                Round_g     => FixRound_Trunc_c,
397	                Saturate_g  => FixSaturate_None_c,
398	                OpRegs_g    => 1,
399	                RoundReg_g  => "NO",
400	                SatReg_g    => "NO"
401	            )
402	            port map (
403	                Clk         => Clk,
404	                Rst         => Rst,
405	                In_Valid    => In_Valid_Reg,
406	                In_A        => In_Mag_Reg,
407	                In_B        => GcCoef_c,
408	                Out_Valid   => ProcValid,
409	                Out_Result  => ProcMag
410	            );
411	
412	    end generate;
413	
414	    -- Compensation EnablDisabled
415	    g_no_gain_comp : if compareNoCase(GainCorrCoefFmt_g, "NONE") generate
416	        signal In_Mag_Reg   : std_logic_vector(cl_fix_width(InMagFmt_c)-1 downto 0);
417	        signal In_Ang_Reg   : std_logic_vector(cl_fix_width(InAngFmt_c)-1 downto 0);
418	        signal In_Valid_Reg : std_logic;
419	    begin
420	
421	        p_registers : process (Clk) is
422	        begin
423	            if rising_edge(Clk) then
424	                -- Input Regiseter
425	                In_Mag_Reg   <= In_Mag;
426	                In_Ang_Reg   <= In_Ang;
427	                In_Valid_Reg <= In_Ready_I and In_Valid;
428	
429	                -- Reset
430	                if Rst = '1' then
431	                    In_Valid_Reg <= '0';
432	                end if;
433	            end if;
434	        end process;
435	
436	        -- Directly assign inputs (register is in main cordic process)
437	        ProcAng   <= In_Ang_Reg;
438	        ProcMag   <= cl_fix_resize(In_Mag_Reg, InMagFmt_c, IntXyFmt_c, Trunc_s, None_s);
439	        ProcValid <= In_Valid_Reg;
440	
441	    end generate;
442	
443	    -- *** Output Conditioning ***
444	    i_resize_i : entity work.olo_fix_resize
445	        generic map (
446	            AFmt_g      => to_string(IntXyFmt_c),
447	            ResultFmt_g => to_string(OutFmt_c),
448	            Round_g     => to_string(Round_c),
449	            Saturate_g  => to_string(Saturate_c),
450	            RoundReg_g  => choose(Round_c = Trunc_s, "NO", "YES"),
451	            SatReg_g    => choose(Saturate_c = None_s, "NO", "YES")
452	        )
453	        port map (
454	            Clk         => Clk,
455	            Rst         => Rst,
456	            In_Valid    => QcVld,
457	            In_A        => XQc,
458	            Out_Valid   => Out_Valid,
459	            Out_Result  => Out_I
460	        );
461	
462	    i_resize_q : entity work.olo_fix_resize
463	        generic map (
464	            AFmt_g      => to_string(IntXyFmt_c),
465	            ResultFmt_g => to_string(OutFmt_c),
466	            Round_g     => to_string(Round_c),
467	            Saturate_g  => to_string(Saturate_c),
468	            RoundReg_g  => choose(Round_c = Trunc_s, "NO", "YES"),
469	            SatReg_g    => choose(Saturate_c = None_s, "NO", "YES")
470	        )
471	        port map (
472	            Clk         => Clk,
473	            Rst         => Rst,
474	            In_Valid    => QcVld,
475	            In_A        => YQc,
476	            Out_Result  => Out_Q
477	        );
478	
479	end architecture;
