1	---------------------------------------------------------------------------------------------------
2	-- Copyright (c) 2018 by Paul Scherrer Institute, Switzerland
3	-- Copyright (c) 2025-2026 by Oliver Bruendler
4	-- Authors: Oliver Bruendler
5	---------------------------------------------------------------------------------------------------
6	
7	---------------------------------------------------------------------------------------------------
8	-- Description
9	---------------------------------------------------------------------------------------------------
10	-- This entity implements a vectoring CORDIC algorithm in either pipelined or serial mode.
11	--
12	-- Documentation:
13	-- https://github.com/open-logic/open-logic/blob/main/doc/fix/olo_fix_cordic_vect.md
14	--
15	-- Note: The link points to the documentation of the latest release. If you
16	--       use an older version, the documentation might not match the code.
17	
18	---------------------------------------------------------------------------------------------------
19	-- Libraries
20	---------------------------------------------------------------------------------------------------
21	library ieee;
22	    use ieee.std_logic_1164.all;
23	    use ieee.numeric_std.all;
24	    use ieee.math_real.all;
25	
26	library work;
27	    use work.olo_base_pkg_math.all;
28	    use work.olo_base_pkg_string.all;
29	    use work.olo_base_pkg_array.all;
30	    use work.en_cl_fix_pkg.all;
31	    use work.olo_fix_pkg.all;
32	
33	---------------------------------------------------------------------------------------------------
34	-- Entity Declaration
35	---------------------------------------------------------------------------------------------------
36	entity olo_fix_cordic_vect is
37	    generic (
38	        InFmt_g           : string;
39	        OutMagFmt_g       : string;
40	        OutAngFmt_g       : string;
41	        IntXyFmt_g        : string                 := "AUTO";
42	        IntAngFmt_g       : string                 := "AUTO";
43	        Iterations_g      : positive range 3 to 32 := 16;
44	        Mode_g            : string                 := "PIPELINED";
45	        GainCorrCoefFmt_g : string                 := "(0,0,17)";
46	        Round_g           : string                 := FixRound_Trunc_c;
47	        Saturate_g        : string                 := FixSaturate_Warn_c
48	    );
49	    port (
50	        -- Control Signals
51	        Clk       : in    std_logic;
52	        Rst       : in    std_logic;
53	        -- Input
54	        In_Valid  : in    std_logic := '1';
55	        In_Ready  : out   std_logic;
56	        In_I      : in    std_logic_vector(fixFmtWidthFromString(InFmt_g)-1 downto 0);
57	        In_Q      : in    std_logic_vector(fixFmtWidthFromString(InFmt_g)-1 downto 0);
58	        -- Output
59	        Out_Valid : out   std_logic;
60	        Out_Mag   : out   std_logic_vector(fixFmtWidthFromString(OutMagFmt_g)-1 downto 0);
61	        Out_Ang   : out   std_logic_vector(fixFmtWidthFromString(OutAngFmt_g)-1 downto 0)
62	    );
63	end entity;
64	
65	---------------------------------------------------------------------------------------------------
66	-- Architecture Declaration
67	---------------------------------------------------------------------------------------------------
68	architecture rtl of olo_fix_cordic_vect is
69	
70	    -- Constants
71	    constant EntityName_c : string := "olo_fix_cordic_vect";
72	
73	    -- Formats
74	    constant InFmt_c           : FixFormat_t   := cl_fix_format_from_string(InFmt_g);
75	    constant OutMagFmt_c       : FixFormat_t   := cl_fix_format_from_string(OutMagFmt_g);
76	    constant OutAngFmt_c       : FixFormat_t   := cl_fix_format_from_string(OutAngFmt_g);
77	    constant IntXyFmt_c        : FixFormat_t   := choose(compareNoCase(IntXyFmt_g, "AUTO"),
78	                                                         (1, InFmt_c.I + 2, max(OutMagFmt_c.F, OutAngFmt_c.F - InFmt_c.I) + 4),
79	                                                         fixFmtFromStringTolerant(IntXyFmt_g));
80	    constant IntAngFmt_c       : FixFormat_t   := choose(compareNoCase(IntAngFmt_g, "AUTO"),
81	                                                         (1, -1, OutAngFmt_c.F + 3),
82	                                                         fixFmtFromStringTolerant(IntAngFmt_g));
83	    constant GainCorrCoefFmt_c : FixFormat_t   := choose(compareNoCase(GainCorrCoefFmt_g, "NONE"),
84	                                                         FixFmt_Unused_c,
85	                                                         fixFmtFromStringTolerant(GainCorrCoefFmt_g));
86	    constant Round_c           : FixRound_t    := cl_fix_round_from_string(Round_g);
87	    constant Saturate_c        : FixSaturate_t := cl_fix_saturate_from_string(Saturate_g);
88	
89	    -- For angles in scaled radians, there is no difference between unsigned or signed (two's
90	    -- compliment). However, AngleTableReal_c has been hard-coded as unsigned, so we force that.
91	    constant TableFmt_c            : FixFormat_t := (0, -2, IntAngFmt_c.F);
92	    -- For consistency, we also use an unsigned AngleIntFmt for other angle conversions from real.
93	    constant UnsignedAngleIntFmt_c : FixFormat_t := (0, 0, IntAngFmt_c.F);
94	
95	    -- *** Constants ***
96	    constant AngleTableReal_c : RealArray_t(0 to 31) := (0.125,              0.0737918088252,    0.0389895651887,    0.0197917120803,
97	                                                         0.00993426215277,   0.00497197391179,   0.00248659363948,   0.00124337269683,
98	                                                         0.000621695834357,  0.000310849102962,  0.000155424699705,  7.77123683806e-05,
99	                                                         3.88561865063e-05,  1.94280935426e-05,  9.71404680751e-06,  4.85702340828e-06,
100	                                                         2.4285117047e-06,   1.21425585242e-06,  6.0712792622e-07,   3.03563963111e-07,
101	                                                         1.51781981556e-07,  7.58909907779e-08,  3.7945495389e-08,   1.89727476945e-08,
102	                                                         9.48637384724e-09,  4.74318692362e-09,  2.37159346181e-09,  1.1857967309e-09,
103	                                                         5.92898365452e-10,  2.96449182726e-10,  1.48224591363e-10,  7.41122956816e-11);
104	    type AngleTable_t is array (0 to Iterations_g-1) of std_logic_vector(cl_fix_width(TableFmt_c)-1 downto 0);
105	
106	    function angleTableStdlv return AngleTable_t is
107	        variable Table_v : AngleTable_t;
108	    begin
109	
110	        for i in 0 to Iterations_g-1 loop
111	            Table_v(i) := cl_fix_from_real(AngleTableReal_c(i), TableFmt_c);
112	        end loop;
113	
114	        return Table_v;
115	    end function;
116	
117	    constant AngleTable_c : AngleTable_t := angleTableStdlv;
118	
119	    function cordicGain (iterations : integer) return real is
120	        variable Gain_v : real := 1.0;
121	    begin
122	
123	        for i in 0 to iterations-1 loop
124	            Gain_v := Gain_v * sqrt(1.0+2.0**(-2.0*real(i)));
125	        end loop;
126	
127	        return Gain_v;
128	    end function;
129	
130	    constant GcCoef_c     : std_logic_vector(cl_fix_width(GainCorrCoefFmt_c)-1 downto 0) := cl_fix_from_real(1.0/cordicGain(Iterations_g), GainCorrCoefFmt_c);
131	    constant AngInt_0_5_c : std_logic_vector(cl_fix_width(IntAngFmt_c)-1 downto 0)       := cl_fix_from_real(0.5, UnsignedAngleIntFmt_c);
132	    constant AngInt_1_0_c : std_logic_vector(cl_fix_width(IntAngFmt_c)-1 downto 0)       := cl_fix_from_real(0.0, UnsignedAngleIntFmt_c);
133	
134	    -- *** Functions ***
135	    -- Cordic step for X
136	    function cordicStepx (
137	        xLast       : std_logic_vector;
138	        yLast       : std_logic_vector;
139	        shift       : integer) return std_logic_vector is
140	        -- Declarations
141	        constant YShifted_c : std_logic_vector := fixDynShift(yLast, IntXyFmt_c, -shift, -Iterations_g, 0, IntXyFmt_c, Trunc_s, None_s);
142	    begin
143	
144	        if signed(yLast) < 0 then
145	            return cl_fix_sub(xLast, IntXyFmt_c,
146	                              YShifted_c, IntXyFmt_c,
147	                              IntXyFmt_c, Trunc_s, None_s);
148	        else
149	            return cl_fix_add(xLast, IntXyFmt_c,
150	                              YShifted_c, IntXyFmt_c,
151	                              IntXyFmt_c, Trunc_s, None_s);
152	
153	        end if;
154	    end function;
155	
156	    -- Cordic step for Y
157	    function cordicStepy (
158	        xLast       : std_logic_vector;
159	        yLast       : std_logic_vector;
160	        shift       : integer) return std_logic_vector is
161	        -- Declarations
162	        constant XShifted_c : std_logic_vector := fixDynShift(xLast, IntXyFmt_c, -shift, -Iterations_g, 0, IntXyFmt_c, Trunc_s, None_s);
163	    begin
164	
165	        if signed(yLast) < 0 then
166	            return  cl_fix_add(yLast, IntXyFmt_c,
167	                               XShifted_c, IntXyFmt_c,
168	                               IntXyFmt_c, Trunc_s, None_s);
169	        else
170	            return  cl_fix_sub(yLast, IntXyFmt_c,
171	                               XShifted_c, IntXyFmt_c,
172	                               IntXyFmt_c, Trunc_s, None_s);
173	        end if;
174	    end function;
175	
176	    -- Cordic step for Z
177	    function cordicStepz (
178	        zLast       : std_logic_vector;
179	        yLast       : std_logic_vector;
180	        iteration   : integer) return std_logic_vector is
181	        -- Declarations
182	        constant Atan_c : std_logic_vector(cl_fix_width(TableFmt_c)-1 downto 0) := AngleTable_c(iteration);
183	    begin
184	        if signed(yLast) < 0 then
185	            return  cl_fix_sub(zLast, IntAngFmt_c,
186	                               Atan_c, TableFmt_c,
187	                               IntAngFmt_c, Trunc_s, None_s);
188	        else
189	            return  cl_fix_add(zLast, IntAngFmt_c,
190	                               Atan_c, TableFmt_c,
191	                               IntAngFmt_c, Trunc_s, None_s);
192	        end if;
193	    end function;
194	
195	    -- Types
196	    type IntArr_t is array (natural range <>) of std_logic_vector(cl_fix_width(IntXyFmt_c)-1 downto 0);
197	    type AngArr_t is array (natural range <>) of std_logic_vector(cl_fix_width(IntAngFmt_c)-1 downto 0);
198	
199	    -- Gain Correction Signals
200	    signal GcAng : std_logic_vector(cl_fix_width(OutAngFmt_c)-1 downto 0);
201	    signal GcMag : std_logic_vector(cl_fix_width(IntXyFmt_c)-1 downto 0);
202	    signal GcVld : std_logic;
203	
204	begin
205	
206	    -- *** Assertions ***
207	    assert InFmt_c.S = 1
208	        report errorMessage(EntityName_c, "InFmt_g must be signed")
209	        severity error;
210	    assert OutMagFmt_c.S = 0
211	        report errorMessage(EntityName_c, "OutMagFmt_g must be unsigned")
212	        severity error;
213	    assert OutAngFmt_c.S + OutAngFmt_c.I = 0
214	        report errorMessage(EntityName_c, "OutAngFmt_g must be (0, 0, x)")
215	        severity error;
216	    assert IntXyFmt_c.S = 1
217	        report errorMessage(EntityName_c, "IntXyFmt_g must be signed")
218	        severity error;
219	    assert IntAngFmt_c.S = 1
220	        report errorMessage(EntityName_c, "IntAngFmt_g must be signed")
221	        severity error;
222	    assert IntAngFmt_c.I = -1
223	        report errorMessage(EntityName_c, "IntAngFmt_g must be (1,-1,x)")
224	        severity error;
225	    assert compareNoCase(Mode_g, "PIPELINED") or compareNoCase(Mode_g, "SERIAL")
226	        report errorMessage(EntityName_c, "Mode_g must be PIPELINED or SERIAL")
227	        severity error;
228	
229	    -- *** Pipelined Implementation ***
230	    g_pipelined : if compareNoCase(Mode_g, "PIPELINED") generate
231	        signal IReg, Qreg : std_logic_vector(cl_fix_width(InFmt_c)-1 downto 0);
232	        signal VldReg     : std_logic;
233	        signal X, Y       : IntArr_t(0 to Iterations_g);
234	        signal Z          : AngArr_t(0 to Iterations_g);
235	        signal Vld        : std_logic_vector(0 to Iterations_g);
236	        signal Quad       : StlvArray2_t(0 to Iterations_g);
237	    begin
238	        -- Pipelined implementation can take a sample every clock cycle
239	        In_Ready <= '1';
240	
241	        -- Implementation
242	        p_cordic_pipelined : process (Clk) is
243	        begin
244	            if rising_edge(Clk) then
245	                -- Input registering
246	                VldReg <= In_Valid;
247	                IReg   <= In_I;
248	                Qreg   <= In_Q;
249	
250	                -- Map to quadrant one
251	                -- No rounding or saturation because IntXyFmt_c is checked to have sufficient int and frac bits
252	                X(0)    <= cl_fix_abs(IReg, InFmt_c, IntXyFmt_c, Trunc_s, None_s);
253	                Y(0)    <= cl_fix_abs(Qreg, InFmt_c, IntXyFmt_c, Trunc_s, None_s);
254	                Z(0)    <= (others => '0');
255	                Quad(0) <= IReg(IReg'left) & Qreg(Qreg'left);
256	                Vld(0)  <= VldReg;
257	
258	                -- Cordic Iterations_g
259	                Vld(1 to Vld'high)   <= Vld(0 to Vld'high-1);
260	                Quad(1 to Quad'high) <= Quad(0 to Quad'high-1);
261	
262	                for i in 0 to Iterations_g-1 loop
263	                    X(i+1) <= cordicStepx(X(i), Y(i), i);
264	                    Y(i+1) <= cordicStepy(X(i), Y(i), i);
265	                    Z(i+1) <= cordicStepz(Z(i), Y(i), i);
266	                end loop;
267	
268	                -- Output
269	                GcVld <= Vld(Iterations_g);
270	                GcMag <= X(Iterations_g);
271	
272	                case Quad(Iterations_g) is
273	                    -- Normalized angles are never saturated. With 1 non-fractional bit, wrapping is correct behavior.
274	                    when "00" => GcAng <= cl_fix_resize(Z(Iterations_g), IntAngFmt_c, OutAngFmt_c, Trunc_s, None_s);
275	                    when "10" => GcAng <= cl_fix_sub(AngInt_0_5_c, IntAngFmt_c, Z(Iterations_g), IntAngFmt_c, OutAngFmt_c, Trunc_s, None_s);
276	                    when "11" => GcAng <= cl_fix_add(AngInt_0_5_c, IntAngFmt_c, Z(Iterations_g), IntAngFmt_c, OutAngFmt_c, Trunc_s, None_s);
277	                    when "01" => GcAng <= cl_fix_sub(AngInt_1_0_c, IntAngFmt_c, Z(Iterations_g), IntAngFmt_c, OutAngFmt_c, Trunc_s, None_s);
278	                    -- coverage off
279	                    when others => null; -- unreachable
280	                    -- coverage on
281	                end case;
282	
283	                -- Reset
284	                if Rst = '1' then
285	                    Vld    <= (others => '0');
286	                    VldReg <= '0';
287	                    GcVld  <= '0';
288	                end if;
289	            end if;
290	        end process;
291	
292	    end generate;
293	
294	    -- *** Serial Implementation ***
295	    g_serial : if compareNoCase(Mode_g, "SERIAL") generate
296	        -- Signals
297	        signal Xin, Yin   : std_logic_vector(cl_fix_width(IntXyFmt_c)-1 downto 0);
298	        signal XIn_Valid  : std_logic;
299	        signal Quadin     : std_logic_vector(1 downto 0);
300	        signal X, Y       : std_logic_vector(cl_fix_width(IntXyFmt_c)-1 downto 0);
301	        signal Z          : std_logic_vector(cl_fix_width(IntAngFmt_c)-1 downto 0);
302	        signal CordVld    : std_logic;
303	        signal IterCnt    : integer range 0 to Iterations_g-1;
304	        signal Quad       : std_logic_vector(1 downto 0);
305	        signal InReadyCnt : integer range 0 to Iterations_g-1;
306	        signal In_Ready_I : std_logic;
307	
308	        -- Constants
309	        constant Z0_c : std_logic_vector(cl_fix_width(IntAngFmt_c)-1 downto 0) := (others => '0');
310	    begin
311	        In_Ready <= In_Ready_I;
312	
313	        p_cordic_serial : process (Clk) is
314	        begin
315	            if rising_edge(Clk) then
316	                -- In Ready Handling
317	                if In_Ready_I = '1' and In_Valid = '1' then
318	                    In_Ready_I <= '0';
319	                    InReadyCnt <= 0;
320	                end if;
321	
322	                if In_Ready_I = '0' then
323	                    InReadyCnt <= InReadyCnt + 1;
324	                    -- Block for Iterations_g-1 cycles
325	                    if InReadyCnt = Iterations_g - 2 then
326	                        In_Ready_I <= '1';
327	                    end if;
328	                end if;
329	
330	                -- Input latching
331	                if XIn_Valid = '0' and In_Valid = '1' then
332	                    XIn_Valid <= '1';
333	                    -- Map to quadrant one
334	                    -- No rounding or saturation because IntXyFmt_c is checked to have sufficient int and frac bits
335	                    Xin    <= cl_fix_abs(In_I, InFmt_c, IntXyFmt_c, Trunc_s, None_s);
336	                    Yin    <= cl_fix_abs(In_Q, InFmt_c, IntXyFmt_c, Trunc_s, None_s);
337	                    Quadin <= In_I(In_I'left) & In_Q(In_Q'left);
338	                end if;
339	
340	                -- CORDIC loop
341	                CordVld <= '0';
342	                if IterCnt = 0 then
343	                    -- Start of calculation
344	                    if XIn_Valid = '1' then
345	                        Y         <= cordicStepy(Xin, Yin, 0);
346	                        X         <= cordicStepx(Xin, Yin, 0);
347	                        Quad      <= Quadin;
348	                        Z         <= cordicStepz(Z0_c, Yin, 0);
349	                        IterCnt   <= IterCnt+1;
350	                        XIn_Valid <= '0';
351	                    end if;
352	                else
353	                    -- Normal Calculation Step
354	                    X <= cordicStepx(X, Y, IterCnt);
355	                    Y <= cordicStepy(X, Y, IterCnt);
356	                    Z <= cordicStepz(Z, Y, IterCnt);
357	
358	                    if IterCnt = Iterations_g-1 then
359	                        IterCnt <= 0;
360	                        CordVld <= '1';
361	                    else
362	                        IterCnt <= IterCnt+1;
363	                    end if;
364	                end if;
365	
366	                -- Output
367	                GcVld <= CordVld;
368	                GcMag <= X;
369	
370	                case Quad is
371	                    -- Normalized angles are never saturated. With 1 non-fractional bit, wrapping is correct behavior.
372	                    when "00" => GcAng <= cl_fix_resize(Z, IntAngFmt_c, OutAngFmt_c, Trunc_s, None_s);
373	                    when "10" => GcAng <= cl_fix_sub(AngInt_0_5_c, IntAngFmt_c, Z, IntAngFmt_c, OutAngFmt_c, Trunc_s, None_s);
374	                    when "11" => GcAng <= cl_fix_add(AngInt_0_5_c, IntAngFmt_c, Z, IntAngFmt_c, OutAngFmt_c, Trunc_s, None_s);
375	                    when "01" => GcAng <= cl_fix_sub(AngInt_1_0_c, IntAngFmt_c, Z, IntAngFmt_c, OutAngFmt_c, Trunc_s, None_s);
376	                    -- coverage off
377	                    when others => null; -- unreachable
378	                    -- coverage on
379	                end case;
380	
381	                -- Reset
382	                if Rst = '1' then
383	                    XIn_Valid  <= '0';
384	                    IterCnt    <= 0;
385	                    GcVld      <= '0';
386	                    CordVld    <= '0';
387	                    In_Ready_I <= '1';
388	                end if;
389	            end if;
390	        end process;
391	
392	    end generate;
393	
394	    -- *** Gain Correction ***
395	    -- No correction
396	    g_no_gain_comp : if compareNoCase(GainCorrCoefFmt_g, "NONE") generate
397	
398	        -- Resize Magnitued
399	        i_resize_mag : entity work.olo_fix_resize
400	            generic map (
401	                AFmt_g      => to_string(IntXyFmt_c),
402	                ResultFmt_g => to_string(OutMagFmt_c),
403	                Round_g     => to_string(Round_c),
404	                Saturate_g  => to_string(Saturate_c),
405	                RoundReg_g  => "YES",
406	                SatReg_g    => "YES"
407	            )
408	            port map (
409	                Clk         => Clk,
410	                Rst         => Rst,
411	                In_Valid    => GcVld,
412	                In_A        => GcMag,
413	                Out_Valid   => Out_Valid,
414	                Out_Result  => Out_Mag
415	            );
416	
417	        -- Delay Angle
418	        i_delay_angle : entity work.olo_base_delay
419	            generic map (
420	                Width_g         => cl_fix_width(OutAngFmt_c),
421	                Delay_g         => 2,
422	                RstState_g      => false
423	            )
424	            port map (
425	                Clk      => Clk,
426	                Rst      => Rst,
427	                In_Data  => GcAng,
428	                Out_Data => Out_Ang
429	            );
430	
431	    end generate;
432	
433	    -- Compensation Enabled
434	    g_gain_comp : if not compareNoCase(GainCorrCoefFmt_g, "NONE") generate
435	
436	        i_mult_mag : entity work.olo_fix_mult
437	            generic map (
438	                AFmt_g      => to_string(IntXyFmt_c),
439	                BFmt_g      => to_string(GainCorrCoefFmt_c),
440	                ResultFmt_g => to_string(OutMagFmt_c),
441	                Round_g     => to_string(Round_c),
442	                Saturate_g  => to_string(Saturate_c),
443	                RoundReg_g  => "YES",
444	                SatReg_g    => "YES",
445	                OpRegs_g    => 1
446	            )
447	            port map (
448	                Clk         => Clk,
449	                Rst         => Rst,
450	                In_Valid    => GcVld,
451	                In_A        => GcMag,
452	                In_B        => GcCoef_c,
453	                Out_Valid   => Out_Valid,
454	                Out_Result  => Out_Mag
455	            );
456	
457	        -- Delay Angle
458	        i_delay_angle : entity work.olo_base_delay
459	            generic map (
460	                Width_g         => cl_fix_width(OutAngFmt_c),
461	                Delay_g         => 3,
462	                RstState_g      => false
463	            )
464	            port map (
465	                Clk      => Clk,
466	                Rst      => Rst,
467	                In_Data  => GcAng,
468	                Out_Data => Out_Ang
469	            );
470	
471	    end generate;
472	
473	end architecture;
474

