5	
6	---------------------------------------------------------------------------------------------------
7	-- Libraries
8	---------------------------------------------------------------------------------------------------
9	library ieee;
10	    use ieee.std_logic_1164.all;
11	    use ieee.numeric_std.all;
12	    use ieee.math_real.all;
13	
14	library vunit_lib;
15	    context vunit_lib.vunit_context;
16	    context vunit_lib.com_context;
17	    context vunit_lib.vc_context;
18	    use vunit_lib.queue_pkg.all;
19	    use vunit_lib.sync_pkg.all;
20	
21	library olo;
22	    use olo.en_cl_fix_pkg.all;
23	    use olo.olo_fix_pkg.all;
24	    use olo.olo_base_pkg_math.all;
25	
26	library work;
27	    use work.olo_test_fix_stimuli_pkg.all;
28	    use work.olo_test_fix_checker_pkg.all;
29	
30	---------------------------------------------------------------------------------------------------
31	-- Entity
32	---------------------------------------------------------------------------------------------------
33	-- vunit: run_all_in_same_sim
34	entity olo_fix_cordic_vect_tb is
35	    generic (
36	        InFmt_g           : string   := "(1,0,16)";
37	        OutAngFmt_g       : string   := "(0,0,16)";
38	        OutMagFmt_g       : string   := "(0,0,15)";
39	        IntXyFmt_g        : string   := "AUTO";
40	        IntAngFmt_g       : string   := "AUTO";
41	        Iterations_g      : positive := 16;
42	        Mode_g            : string   := "PIPELINED";
43	        GainCorrCoefFmt_g : string   := "(0,0,17)";
44	        Round_g           : string   := "Trunc_s";
45	        Saturate_g        : string   := "Sat_s";
46	        runner_cfg        : string
47	    );
48	end entity;
49	
50	architecture sim of olo_fix_cordic_vect_tb is
51	
52	    -----------------------------------------------------------------------------------------------
53	    -- TB Defnitions
54	    -----------------------------------------------------------------------------------------------
55	    constant Clk_Frequency_c : real := 100.0e6; -- 100 MHz
56	    constant Clk_Period_c    : time := (1 sec) / Clk_Frequency_c;
57	
58	    -- Latency calculation
59	    constant GainLatency_c     : natural := choose(GainCorrCoefFmt_g = "NONE", 0, 1);
60	    constant BaseLatency_c     : natural := choose(Mode_g = "PIPELINED", 5, 4);
61	    constant ExpectedLatency_c : natural := BaseLatency_c + GainLatency_c + Iterations_g;
62	
63	    -----------------------------------------------------------------------------------------------
64	    -- Interface Signals
65	    -----------------------------------------------------------------------------------------------
66	    signal Clk       : std_logic                                                   := '0';
67	    signal Rst       : std_logic                                                   := '0';
68	    signal In_Valid  : std_logic                                                   := '0';
69	    signal In_Ready  : std_logic;
70	    signal In_I      : std_logic_vector(fixFmtWidthFromString(InFmt_g)-1 downto 0) := (others => '0');
71	    signal In_Q      : std_logic_vector(fixFmtWidthFromString(InFmt_g)-1 downto 0) := (others => '0');
72	    signal Out_Valid : std_logic;
73	    signal Out_Ang   : std_logic_vector(fixFmtWidthFromString(OutAngFmt_g)-1 downto 0);
74	    signal Out_Mag   : std_logic_vector(fixFmtWidthFromString(OutMagFmt_g)-1 downto 0);
75	
76	    -----------------------------------------------------------------------------------------------
77	    -- TB Defnitions
78	    -----------------------------------------------------------------------------------------------
79	    -- *** Verification Compnents ***
80	    constant StimuliI_c   : olo_test_fix_stimuli_t := new_olo_test_fix_stimuli;
81	    constant StimuliQ_c   : olo_test_fix_stimuli_t := new_olo_test_fix_stimuli;
82	    constant CheckerMag_c : olo_test_fix_checker_t := new_olo_test_fix_checker;
83	    constant CheckerAng_c : olo_test_fix_checker_t := new_olo_test_fix_checker;
84	
85	    -- *** Constants ***
86	    constant InIFile_c    : string := output_path(runner_cfg) & "InI.fix";
